-- ============================================================
-- IMPORT LEGACY CUSTOMERS FROM DATASYSTEM
-- Generated from: Clientes Venda na Live.xls
-- Total: 1380 customers (9 skipped - missing name/phone)
-- Strategy: ON CONFLICT DO NOTHING (skip duplicates)
-- ============================================================

-- Step 1: Insert into customers (skip if phone already exists)
ON CONFLICT (phone) DO NOTHING;

-- Step 2: Insert instagram_identities for live auto-recognition
-- Links each @instagram -> phone + customer_id
SELECT
  lower(trim(replace(c.instagram_handle, '@', ''))),
  c.instagram_handle,
  c.phone,
  c.id
FROM public.customers c
WHERE c.instagram_handle IS NOT NULL
  AND c.instagram_handle != ''
  AND NOT EXISTS (
    SELECT 1 FROM public.instagram_identities ii
    WHERE ii.instagram_handle_normalized = lower(trim(replace(c.instagram_handle, '@', '')))
  );
